const webhookItem = $input.first().json;
const input = webhookItem.body ?? webhookItem;
const errors = [];

if (typeof input.customer_name !== 'string' || input.customer_name.trim() === '') {
  errors.push('customer_name is required');
}
if (typeof input.customer_email !== 'string' || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(input.customer_email)) {
  errors.push('customer_email is required and must be valid');
}
if (!Array.isArray(input.items) || input.items.length === 0) {
  errors.push('items array is required and must contain at least one item');
} else {
  input.items.forEach((item, i) => {
    if (typeof item.label !== 'string' || item.label.trim() === '') errors.push(`items[${i}].label is required`);
    if (typeof item.quantity !== 'number' || !Number.isFinite(item.quantity) || item.quantity <= 0) errors.push(`items[${i}].quantity must be a number > 0`);
    if (typeof item.unit_price !== 'number' || !Number.isFinite(item.unit_price) || item.unit_price <= 0) errors.push(`items[${i}].unit_price must be a number > 0`);
  });
}
if (input.customer_country && !/^[A-Z]{2}$/.test(input.customer_country)) {
  errors.push('customer_country must be an uppercase ISO alpha-2 code');
}
if (input.due_date && !/^\d{4}-\d{2}-\d{2}$/.test(input.due_date)) {
  errors.push('due_date must use YYYY-MM-DD format');
}
if (errors.length > 0) throw new Error('Validation failed: ' + errors.join('; '));

return [{ json: {
  customer_name: input.customer_name.trim(),
  customer_email: input.customer_email.trim().toLowerCase(),
  customer_address: typeof input.customer_address === 'string' ? input.customer_address : '',
  customer_postal_code: typeof input.customer_postal_code === 'string' ? input.customer_postal_code : '00000',
  customer_city: typeof input.customer_city === 'string' ? input.customer_city : 'Non renseigné',
  customer_country: input.customer_country || 'FR',
  items: input.items.map(item => ({
    label: item.label.trim(),
    quantity: item.quantity,
    unit_price: item.unit_price,
    vat_rate: item.vat_rate || 'FR_200'
  })),
  due_date: input.due_date || new Date(Date.now() + 30 * 86400000).toISOString().split('T')[0],
  currency: input.currency || 'EUR',
  reference: input.reference || null,
  send_email: input.send_email === true
} }];

// Refs: 'Set Customer ID', 'Code Validate Payload'
const data = $('Code Validate Payload').first().json;
const customerId = $('Set Customer ID').first().json.customer_id;

const invoiceLines = data.items.map(item => ({
  label: item.label,
  quantity: item.quantity,
  unit: 'piece',
  raw_currency_unit_price: String(item.unit_price.toFixed(2)),
  vat_rate: item.vat_rate
}));

const today = new Date().toISOString().split('T')[0];

const payload = {
  customer_id: customerId,
  date: today,
  deadline: data.due_date,
  currency: data.currency,
  invoice_lines: invoiceLines,
  draft: false
};

if (data.reference) {
  payload.external_reference = data.reference;
}

return [{ json: payload }];

const statusCode = $input.first().json.statusCode;
const attempt = $('Set Email Attempt').first().json.attempt;
return [{ json: {
  attempt,
  status_code: statusCode,
  retry: statusCode === 409 && attempt < 5
} }];
